class Solution:
    def maximumWhiteTiles(self, tiles, carpetLen):
        best = 0
        for l, r in tiles:
            for start in (l, max(l, r - carpetLen + 1)):
                end = start + carpetLen - 1
                covered = 0
                for a, b in tiles:
                    lo = max(a, start)
                    hi = min(b, end)
                    if hi >= lo:
                        covered += hi - lo + 1
                if covered > best:
                    best = covered
        return best

