class Solution:
    def maximumWhiteTiles(self, tiles, carpetLen):
        tiles.sort()
        n = len(tiles)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + (tiles[i][1] - tiles[i][0] + 1)
        best = 0
        j = 0
        for i in range(n):
            start = tiles[i][0]
            end = start + carpetLen - 1
            while j < n and tiles[j][1] <= end:
                j += 1
            covered = prefix[j] - prefix[i]
            if j < n and tiles[j][0] <= end:
                covered += end - tiles[j][0] + 1
            if covered > best:
                best = covered
        return best

